import React from "react";

export default function DashboardCards() {

  const cards = [
    ["Patients", "5000"],
    ["Records", "20000"],
    ["Conflicts", "3175"],
    ["High Risk", "693"]
  ];

  return (
    <div style={{
      display: "grid",
      gridTemplateColumns: "repeat(4,1fr)",
      gap: "20px"
    }}>
      {cards.map((card) => (
        <div
          key={card[0]}
          style={{
            border: "1px solid #ddd",
            borderRadius: "10px",
            padding: "20px"
          }}
        >
          <h3>{card[0]}</h3>
          <h1>{card[1]}</h1>
        </div>
      ))}
    </div>
  );
}
